<template>
  <div class="add-body">
    <!--main-->
    <div class="add-content" style="overflow: hidden">
      <!--con-->
      <div class="add-content_row" style="padding-top:2vh">
        <div class="add-content_col">
          <span><i>*</i>菜单名称</span>
          <span>
            <el-input v-model="addForm['name']" placeholder="请输入分组名称"></el-input>
          </span>
        </div>
        <div class="add-content_col">
          <span><i>*</i>菜单路由</span>
          <span>
            <el-input v-model="addForm['url']" placeholder="请输入菜单路由"></el-input>
          </span>
        </div>
        <div class="add-content_col">
          <span><i>*</i>菜单类型</span>
          <span>
            <el-select v-model="addForm['type']" placeholder="请选择菜单类型">
              <el-option label="目录" value="0"></el-option>
              <el-option label="菜单" value="1"></el-option>
              <el-option label="按钮" value="2"></el-option>
            </el-select>
          </span>
        </div>
        <div class="add-content_col">
          <span><i>*</i>排序</span>
          <span>
            <el-input v-model="addForm['orderNum']" placeholder="请输入排序"></el-input>
          </span>
        </div>
        <div class="add-content_col">
          <span>图标</span>
          <span>
            <el-input v-model="addForm['icon']" placeholder="请输入图标"></el-input>
          </span>
        </div>
      </div>
      <!--菜单权限-->
      <div class="body-con-title">
        <img src="~@/assets/image/srm-circle.png" style="width: 15px;margin-right: 1vh;">菜单权限
      </div>
      <div class="body-con-tree">
        <el-tree
            ref="menuTree"
            :data="menuData"
            show-checkbox
            default-expand-all
            node-key="menuId"
            check-on-click-node
            :check-strictly="true"
            :props="defaultProps"
            @check="changeNode">
           <span slot-scope="{ node, data }">
             <i :class="data.icon"></i>
             <span style="padding-left: 4px;">{{node.label}}</span>
           </span>
        </el-tree>
        <!--菜单权限END!-->
      </div>
      <!--===-->
    </div>
    <!--按钮-->
    <div class="add-btn-box" style="margin-top: 0;  ">
      <div class="add-btn" @click="$emit('CloseDialog')">取 消</div>
      <div class="add-btn" @click="addMenu()">保 存</div>
    </div>
    <!--到底啦！===========================-->
  </div>
</template>
<script>
import {addMenuApi, queryMenuJsonApi, updateMenuApi} from "@/api/System/menu";

export default {
  name: "addMenu",
  props: ['MenuMsg'],
  data() {
    return {

      addForm: {},

      menuData: [],
      defaultProps: {
        children: 'childMenuArray',
        label: 'name'
      },
    }
  },
  created() {
    this.getMenuJson()
    if (this.MenuMsg.type == 'edit') {
      this.addForm = JSON.parse(JSON.stringify(this.MenuMsg.row))
      this.$nextTick(() => {
        this.addForm.type = this.addForm.type + ''
        this.$refs.menuTree.setCheckedKeys([this.addForm.parentId]);
      })
    }
  },
  methods: {
    //获取分组
    getMenuJson() {
      queryMenuJsonApi({pageSize: 10000, currentPage: 1,}).then(res => {
        console.log(res);
        if (res.data.code != '2000') return this.$message.error({
          message: res.data.message,
          showClose: true,
          duration: 1000
        });
        this.menuData = res.data.result
        console.log(this.menuData);
      })
    },
    //保存
    addMenu() {
      console.log(this.$refs.menuTree.getCheckedKeys());
      if (!this.addForm.name) return this.$message.error({message: "菜单名称为必填项！", showClose: true, duration: 1000});
      if (!this.addForm.url) return this.$message.error({message: "菜单路由为必填项！", showClose: true, duration: 1000});
      if (!this.addForm.type) return this.$message.error({message: "菜单类型为必填项！", showClose: true, duration: 1000});
      if (!this.addForm.orderNum) return this.$message.error({message: "菜单排序为必填项！", showClose: true, duration: 1000});

      if (this.$refs.menuTree.getCheckedKeys().length == 0) {
        this.addForm['parentId'] = 0
      } else {
        this.addForm['parentId'] = this.$refs.menuTree.getCheckedKeys()[0]
      }
      if (this.MenuMsg.type == 'edit') {
        updateMenuApi(this.addForm).then(res => {
          console.log(res);
          if (res.data.code != '2000') return this.$message.error({
            message: res.data.message,
            showClose: true,
            duration: 1000
          });
          this.$message.success({message: "编辑菜单成功!", showClose: true, duration: 1000});
          this.addForm = {}
          this.$emit('closeZhbDialog', 0)
        })
      } else {
        addMenuApi(this.addForm).then(res => {
          console.log(res);
          if (res.data.code != '2000') return this.$message.error({
            message: res.data.message,
            showClose: true,
            duration: 1000
          });
          this.$message.success({message: "新建菜单成功!", showClose: true, duration: 1000});
          this.addForm = {}
          this.$emit('closeZhbDialog', 0)
        })
      }
    },
    //节点选中状态发生变化时的回调
    changeNode(data) {
      this.$refs.menuTree.setCheckedKeys([data.menuId]);
    }
  }
}
</script>

<style scoped lang="scss">
.add-body {


  .body-con-title {
    width: 100%;
    font-size: 17px;
    color: #ffffff;
    text-align: left;
    font-weight: bold;
    letter-spacing: 2px;
    margin-bottom: 10px;
    margin-left: 1vw;
    margin-top: 0;
    text-shadow: 0px 4px 0px rgba(10, 40, 95, 0.36);

    background: linear-gradient(0deg, #ffffff 0%, #98deff 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    display: flex;
    align-items: center;

    &.newtitle {
      text-shadow: none !important;
      background: none !important;
      color: #ffffff !important;
      font-weight: normal;
      font-size: 14px;
      -webkit-text-fill-color: #ffffff !important;
    }
  }

  .body-con-tree {
    width: 80%;
    margin: 0 auto;
    height: calc(100% - 35vh);
    overflow: auto;
    background: rgba(0, 31, 63, 0.6);
    border: 2px solid rgba(12, 187, 200, 0.8);
    box-shadow: 0px 0px 13px 0px rgba(2, 138, 185, 0.25);
  }

  .body-con-tree::-webkit-scrollbar {
    width: 0;
  }
}
</style>