<template>
  <LTPages
      is-normal
      :title="'菜单管理'"
  >
    <template v-slot:content>
      <div class="Page-Table-box Menu-Main-box">
        <LTSearchForm
            type="LargeScreen"
            :formConfig="formConfig"
            @setSearchFields="getSearchFields"
            style="margin-top:15px">
        </LTSearchForm>
        <LTActionsForm :buttonConfig="buttonConfig" style="margin: 10px 0;"></LTActionsForm>
        <div class="Menu-table-box">
          <el-table
              :data="tableConfig.tableData"
              row-key="id"
              border
              :expand-row-keys="[0]"
              style="width: 100%;"
              :cell-style="columnStyle"
              :header-cell-style="headerStyle"
              @selection-change="getSelectionTable"
          >
            <el-table-column
                type="selection"
                width="55">
            </el-table-column>
            <el-table-column
                v-for="(item,index) in tableConfig.tableHead"
                :key="index"
                :label="item.label"
                :prop="item.prop"
                :width="item.width"
            >
              <template slot-scope="scope" >
                <span>{{ scope.row[item.prop]}}</span>
              </template>
            </el-table-column>
          </el-table>
        </div>
      </div>
      <!--新增菜单-->
      <LTDialog
          v-if="MenuMsg.isShow"
          :DialogLTMsg="MenuMsg"
          @close="MenuMsg.isShow = false">
        <addMenu :MenuMsg="MenuMsg" @CloseDialog="CloseDialog"></addMenu>
      </LTDialog>
    </template>
  </LTPages>
</template>

<script>
import {deleteMenuApi, queryMenuApi} from "@/api/System/menu";
import { isNull,treeDataTranslate } from "@/utils/table.js";
import addMenu from "./components/addMenu"
export default {
  name: "Menu",
  data() {
    return {
      //搜索配置
      formConfig: {
        labelWidth: "100px",
        itemNum: 5,
        formItemList: [
          {
            id: 1,
            type: 'select',
            prop: 'name',
            label: '菜单分组名称',
            value: '',
            list:[]
          }
        ]
      },
      // 表格上方按钮
      buttonConfig: [
        {
          label: '添加',
          icon: "icon zhb-iconfont zhb-iconxinjian1",
          click: () => {
            this.MenuMsg.type = 'add';
            this.MenuMsg.title = '新增用户';
            this.MenuMsg.isShow = true;
          }
        },
        {
          label: '编辑',
          icon: "icon zhb-iconfont zhb-iconwenbenbianjitianchong",
          click: () => {
            if (this.checkTabelData.length == 0 || this.checkTabelData.length > 1) return this.$message.warning({
              message: "请选择一条表格数据！",
              showClose: true,
              duration: 1000
            });
            this.MenuMsg.type = 'edit'
            this.MenuMsg.row = this.checkTabelData[0];
            this.MenuMsg.title = '编辑菜单';
            this.MenuMsg.isShow = true;
          }
        },
        {
          label: '删除',
          icon: "icon zhb-iconfont zhb-iconshanchu2",
          click: () => {
            console.log(this.checkTabelData);
            if (this.checkTabelData.length == 0) return this.$message.warning({
              message: "请至少选择一条表格数据！",
              showClose: true,
              duration: 1000
            });
            if(this.checkTabelData[0].children && this.checkTabelData[0].children.length) return this.$message.warning({
              message: "该菜单下存在子菜单，不允许删除！",
              showClose: true,
              duration: 1000
            });
            this.$confirm('此操作将删除该菜单, 是否继续?', '提示', {
              confirmButtonText: '确定',
              cancelButtonText: '取消',
              type: 'warning'
            }).then(() => {
              var ids = []
              this.checkTabelData.forEach(item =>{
                ids.push(item.id)
              })
              deleteMenuApi({ids:ids}).then(res=>{
                if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});
                this.queryMenu()
                this.$message({
                  type: 'success',
                  message: '删除成功！'
                });
              })
            }).catch(() => {
              this.$message({
                type: 'info',
                message: '已取消删除'
              });
            });
          }
        }
      ],
      //表格配置
      tableConfig: {
        tableLoading:true,
        tableRefresh: true,
        tableHead: [
          {
            label: '菜单名称',
            prop: 'name',
          },
          {
            label: '菜单路由',
            prop: 'url',
          },
          {
            prop: 'typeName',
            label: "菜单类型"
          },
          {
            prop: 'icon',
            label: "图标"
          }
        ],
        tableData: [],
        columnButton: [],
        columnWidth: '130',
        // tableColWidth:'155',
        total: 10,
        pageSize: 10,
        currentPage: 1,
      },
      //表格勾选
      checkTabelData: [],
      MenuMsg:{
        title:'add',
        isShow: false,
        showCloseBtn: true,
        styles: {
          width: '50%',
          height: '90%'
        }
      },
      //查询参数
      params:{
        // pageSize: 100,
        // currentPage: 1,
      }

    }
  },
  components: {
    addMenu
  },
  created() {
    this.queryMenu()
  },
  methods: {
    getSearchFields(data) {
      if(data.type == 'reset'){
        this.params ={
          pageSize: 20,
          currentPage: 1
        }
      }else {
        this.params.name = data.menuname
      }

      this.params.currentPage = 1;
      this.tableConfig.currentPage = 1;
      this.queryMenu()
    },
    //表格勾选数据
    getSelectionTable(val) {
      console.log(val);
      this.checkTabelData = val
    },
    //表格分页变化回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize
      this.tableConfig.currentPage = page.pageNum
      this.params.pageSize = page.pageSize
      this.params.currentPage = page.pageNum
      this.queryMenu()
    },
    handleCurrentChange(page) {
      this.params.currentPage = page
    },
    queryMenu(){
      this.tableConfig.tableLoading = true
      queryMenuApi(this.params).then(res => {
        console.log(res);
        this.tableConfig.tableLoading = false
        if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});
        if(res.data.result.records && res.data.result.records.length!= 0){
          res.data.result.records.forEach(item => {
            item.id = item.menuId
            if(item.type == 0){
              item.typeName = '目录'
            } else if(item.type == 1){
              item.typeName = '菜单'
            } else if(item.type == 2){
              item.typeName = '按钮'
            }
          })
          this.tableConfig.tableData = treeDataTranslate( res.data.result.records, 'id')
          console.log(this.tableConfig.tableData);
          this.tableConfig.total = res.data.result.total
        } else {
          this.tableConfig.tableData = []
          this.tableConfig.total = 0
        }


      }).catch(()=>{
        this.tableConfig.tableLoading = false
      })
    },
    // 更改单元格样式
    columnStyle({ column }) {
      if(column.property === "groupName") {
        return {
          height: "45px",
          // 'padding': '0px',
          'text-align': 'left',
          "padding-left": '50px',
        };
      }else {
        return {
          height: "45px",
          'padding': '0px',
          'text-align': 'center',
        };
      }
    },
    // 更改表头单元格样式
    headerStyle() {
      return {
        height: "47px",
        'background': '#004077',
        'padding': '0px',
        'text-align': 'center',
        'color': '#ffffff',
        'font-size': '14px',
        'font-weight': 400,
      };
    },
    // 关闭弹窗
    CloseDialog(val) {
      if (val == 0) {
        this.MenuMsg.isShow = false;
        this.queryMenu()
      } else {
        this.MenuMsg.isShow = false;
      }
    }




  },
}
</script>

<style lang="scss" scoped>
.Menu-Main-box {
  margin-top: 15px;
  height: calc(100% - 50px);
  .Menu-table-box{
    height: calc(100% - 130px);
    overflow: auto;
    &::-webkit-scrollbar {
      width: 6px;
    }
    &::-webkit-scrollbar-thumb {
      background: #c0c0c0;
    }
    &::-webkit-scrollbar-track {
      background: #f0f0f0;
    }
  }
}
</style>